import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './HeatmapDashboard.css';

const HeatmapDashboard = ({ language }) => {
  const [adminSession, setAdminSession] = useState(null);
  const [institutionData, setInstitutionData] = useState(null);
  const [riskScore, setRiskScore] = useState(0);
  const [clusterAlerts, setClusterAlerts] = useState([]);
  const navigate = useNavigate();

  const content = {
    en: {
      title: 'Analytics Dashboard',
      subtitle: 'Institution sees the big picture — patterns, hotspots, and risk levels across campus',
      riskScore: 'Institution Risk Score',
      crisisHeatmap: 'Crisis Heatmap',
      crisisBreakdown: 'Crisis Breakdown',
      clusterAlerts: 'Cluster Alert Panel',
      patternInsights: 'Pattern Insights',
      peakTimeAnalysis: 'Peak Time Analysis',
      exportData: 'Export Data',
      viewCases: 'View Cases',
      logoutButton: 'Logout',
      noAccess: 'Access Denied. Please login as an administrator.',
      locations: {
        hostel_a: 'Hostel A',
        hostel_b: 'Hostel B',
        cse_dept: 'CSE Department',
        ece_dept: 'ECE Department',
        library: 'Library',
        common_areas: 'Common Areas',
        cafeteria: 'Cafeteria',
        sports_complex: 'Sports Complex'
      },
      crisisTypes: {
        ragging: 'Ragging',
        harassment: 'Harassment',
        mental_health: 'Mental Health',
        cyberbullying: 'Cyberbullying',
        physical_threat: 'Physical Threat'
      },
      riskLevels: {
        low: 'Low Risk',
        medium: 'Medium Risk',
        high: 'High Risk',
        critical: 'Critical Risk'
      }
    },
    hi: {
      title: 'एनालिटिक्स डैशबोर्ड',
      subtitle: 'संस्थान बड़ी तस्वीर देखता है — कैंपस में पैटर्न, हॉटस्पॉट और जोखिम स्तर',
      riskScore: 'संस्थान जोखिम स्कोर',
      crisisHeatmap: 'संकट हीटमैप',
      crisisBreakdown: 'संकट विभाजन',
      clusterAlerts: 'क्लस्टर अलर्ट पैनल',
      patternInsights: 'पैटर्न अंतर्दृष्टि',
      peakTimeAnalysis: 'पीक टाइम विश्लेषण',
      exportData: 'डेटा निर्यात करें',
      viewCases: 'केस देखें',
      logoutButton: 'लॉगआउट',
      noAccess: 'पहुंच अस्वीकृत। कृपया प्रशासक के रूप में लॉगिन करें।',
      locations: {
        hostel_a: 'हॉस्टल A',
        hostel_b: 'हॉस्टल B',
        cse_dept: 'CSE विभाग',
        ece_dept: 'ECE विभाग',
        library: 'पुस्तकालय',
        common_areas: 'सामान्य क्षेत्र',
        cafeteria: 'कैफेटेरिया',
        sports_complex: 'खेल परिसर'
      },
      crisisTypes: {
        ragging: 'रैगिंग',
        harassment: 'उत्पीड़न',
        mental_health: 'मानसिक स्वास्थ्य',
        cyberbullying: 'साइबरबुलिंग',
        physical_threat: 'शारीरिक खतरा'
      },
      riskLevels: {
        low: 'कम जोखिम',
        medium: 'मध्यम जोखिम',
        high: 'उच्च जोखिम',
        critical: 'गंभीर जोखिम'
      }
    }
  };

  const text = content[language] || content.en;

  // Mock data - in production, this would come from your backend
  const mockData = {
    riskScore: 67,
    heatmapData: {
      hostel_a: { count: 12, severity: 'high' },
      hostel_b: { count: 4, severity: 'medium' },
      cse_dept: { count: 8, severity: 'high' },
      ece_dept: { count: 3, severity: 'low' },
      library: { count: 2, severity: 'low' },
      common_areas: { count: 6, severity: 'medium' },
      cafeteria: { count: 1, severity: 'low' },
      sports_complex: { count: 0, severity: 'safe' }
    },
    crisisBreakdown: {
      ragging: 67,
      harassment: 21,
      mental_health: 9,
      cyberbullying: 3
    },
    clusterAlerts: [
      {
        id: 1,
        location: 'hostel_a',
        type: 'ragging',
        count: 3,
        timeframe: '48 hours',
        recommendation: 'Convene anti-ragging cell today'
      },
      {
        id: 2,
        location: 'cse_dept',
        type: 'harassment',
        count: 4,
        timeframe: '24 hours',
        recommendation: 'ICC investigation required'
      }
    ],
    patternInsights: [
      'Ragging incidents peak between 11pm and 2am',
      'Hostel A has 3x the incident rate of Hostel B',
      'CSE department harassment cases increased 40% this month',
      'Mental health cases spike during exam periods'
    ],
    peakTimes: {
      hours: [0, 2, 1, 0, 0, 0, 1, 2, 3, 4, 6, 8, 12, 15, 18, 14, 10, 8, 6, 4, 3, 2, 4, 6],
      days: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
      dayData: [8, 12, 15, 18, 22, 14, 6]
    }
  };

  useEffect(() => {
    // Check admin authentication
    const session = localStorage.getItem('admin_session');
    const isAuthenticated = localStorage.getItem('admin_authenticated');
    
    if (!session || !isAuthenticated) {
      navigate('/admin');
      return;
    }

    const parsedSession = JSON.parse(session);
    setAdminSession(parsedSession);
    setInstitutionData(mockData);
    setRiskScore(mockData.riskScore);
    setClusterAlerts(mockData.clusterAlerts);
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('admin_session');
    localStorage.removeItem('admin_authenticated');
    navigate('/admin');
  };

  const getRiskLevel = (score) => {
    if (score >= 80) return 'critical';
    if (score >= 60) return 'high';
    if (score >= 40) return 'medium';
    return 'low';
  };

  const getHeatmapColor = (severity) => {
    switch (severity) {
      case 'high': return '#ef4444';
      case 'medium': return '#f59e0b';
      case 'low': return '#10b981';
      default: return '#e5e7eb';
    }
  };

  const exportData = () => {
    const dataToExport = {
      institutionId: adminSession?.institutionId,
      exportDate: new Date().toISOString(),
      riskScore,
      ...institutionData
    };
    
    const blob = new Blob([JSON.stringify(dataToExport, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `analytics-${adminSession?.institutionId}-${Date.now()}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  if (!adminSession) {
    return (
      <div className="analytics-dashboard">
        <div className="no-access">
          <h2>{text.noAccess}</h2>
          <button onClick={() => navigate('/admin')} className="login-redirect">
            Go to Login
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="analytics-dashboard">
      <div className="dashboard-container">
        {/* Header */}
        <div className="dashboard-header">
          <div className="header-info">
            <h1>{text.title}</h1>
            <p className="subtitle">{text.subtitle}</p>
            <div className="admin-info">
              <span className="institution-id">{adminSession.institutionId}</span>
              <span className="role-badge">{adminSession.role}</span>
            </div>
          </div>
          <div className="header-actions">
            <button className="export-btn" onClick={exportData}>
              📊 {text.exportData}
            </button>
            <button className="cases-btn" onClick={() => navigate('/admin/cases')}>
              📋 {text.viewCases}
            </button>
            <button className="logout-btn" onClick={handleLogout}>
              🚪 {text.logoutButton}
            </button>
          </div>
        </div>

        {/* Risk Score Gauge */}
        <div className="risk-score-section">
          <h2>{text.riskScore}</h2>
          <div className="risk-gauge">
            <div className="gauge-container">
              <div 
                className={`gauge-fill ${getRiskLevel(riskScore)}`}
                style={{ '--score': `${riskScore}%` }}
              ></div>
              <div className="gauge-score">{riskScore}</div>
            </div>
            <div className="risk-level">
              {text.riskLevels[getRiskLevel(riskScore)]}
            </div>
          </div>
        </div>

        {/* Cluster Alerts */}
        {clusterAlerts.length > 0 && (
          <div className="cluster-alerts">
            <h2>{text.clusterAlerts}</h2>
            <div className="alerts-grid">
              {clusterAlerts.map(alert => (
                <div key={alert.id} className="alert-card">
                  <div className="alert-header">
                    <span className="alert-icon">⚠️</span>
                    <span className="alert-title">Cluster Alert</span>
                  </div>
                  <div className="alert-content">
                    <p><strong>{alert.count} cases</strong> of {text.crisisTypes[alert.type]} in {text.locations[alert.location]}</p>
                    <p className="timeframe">Within {alert.timeframe}</p>
                    <p className="recommendation">{alert.recommendation}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Crisis Heatmap */}
        <div className="heatmap-section">
          <h2>{text.crisisHeatmap}</h2>
          <div className="heatmap-grid">
            {Object.entries(institutionData?.heatmapData || {}).map(([location, data]) => (
              <div 
                key={location}
                className="heatmap-cell"
                style={{ backgroundColor: getHeatmapColor(data.severity) }}
                title={`${text.locations[location]}: ${data.count} cases`}
              >
                <div className="location-name">{text.locations[location]}</div>
                <div className="case-count">{data.count}</div>
              </div>
            ))}
          </div>
          <div className="heatmap-legend">
            <span style={{ backgroundColor: '#ef4444' }}>High</span>
            <span style={{ backgroundColor: '#f59e0b' }}>Medium</span>
            <span style={{ backgroundColor: '#10b981' }}>Low</span>
            <span style={{ backgroundColor: '#e5e7eb' }}>Safe</span>
          </div>
        </div>

        {/* Crisis Breakdown Chart */}
        <div className="breakdown-section">
          <h2>{text.crisisBreakdown}</h2>
          <div className="breakdown-chart">
            {Object.entries(institutionData?.crisisBreakdown || {}).map(([type, percentage]) => (
              <div key={type} className="breakdown-item">
                <div className="breakdown-label">
                  {text.crisisTypes[type]} ({percentage}%)
                </div>
                <div className="breakdown-bar">
                  <div 
                    className="breakdown-fill"
                    style={{ width: `${percentage}%` }}
                  ></div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Pattern Insights */}
        <div className="insights-section">
          <h2>{text.patternInsights}</h2>
          <div className="insights-list">
            {institutionData?.patternInsights?.map((insight, index) => (
              <div key={index} className="insight-item">
                <span className="insight-icon">💡</span>
                {insight}
              </div>
            ))}
          </div>
        </div>

        {/* Peak Time Analysis */}
        <div className="peak-time-section">
          <h2>{text.peakTimeAnalysis}</h2>
          <div className="time-charts">
            <div className="hourly-chart">
              <h3>Hourly Distribution</h3>
              <div className="chart-bars">
                {institutionData?.peakTimes?.hours?.map((count, hour) => (
                  <div key={hour} className="time-bar">
                    <div 
                      className="bar-fill"
                      style={{ height: `${(count / 22) * 100}%` }}
                    ></div>
                    <span className="bar-label">{hour}</span>
                  </div>
                ))}
              </div>
            </div>
            <div className="daily-chart">
              <h3>Daily Distribution</h3>
              <div className="chart-bars">
                {institutionData?.peakTimes?.dayData?.map((count, index) => (
                  <div key={index} className="time-bar">
                    <div 
                      className="bar-fill"
                      style={{ height: `${(count / 22) * 100}%` }}
                    ></div>
                    <span className="bar-label">{institutionData.peakTimes.days[index]}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HeatmapDashboard;
